Implementasi Observer Pattern yang robust untuk sistem monitoring atau event handling. Saya menggunakan `weakref` untuk mencegah memory leak pada long-running processes dan `try-except` untuk isolasi error antar observer.

```python
import weakref
from abc import ABC, abstractmethod
from typing import Any, List
import logging

# Konfigurasi Logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')
logger = logging.getLogger(__name__)

class Observer(ABC):
    @abstractmethod
    def update(self, subject: 'Subject') -> None:
        pass

class Subject(ABC):
    @abstractmethod
    def attach(self, observer: Observer) -> None:
        pass

    @abstractmethod
    def detach(self, observer: Observer) -> None:
        pass

    @abstractmethod
    def notify(self) -> None:
        pass

class SecurityEventBus(Subject):
    def __init__(self) -> None:
        self._observers: List[weakref.ref] = []
        self._event_data: Any = None

    def attach(self, observer: Observer) -> None:
        # Gunakan weakref untuk menghindari memory leak jika observer tidak di-unregister
        self._observers.append(weakref.ref(observer))

    def detach(self, observer: Observer) -> None:
        self._observers = [ref for ref in self._observers if ref() is not observer]

    def notify(self) -> None:
        # Iterasi salinan list untuk menghindari modifikasi saat iterasi
        # Filter None karena weakref bisa sudah mati
        active_observers = [ref() for ref in self._observers if ref() is not None]

        for observer in active_observers:
            try:
                observer.update(self)
            except Exception as e:
                # Isolasi error: Satu observer gagal tidak boleh menghentikan yang lain
                logger.error(f"Observer {observer.__class__.__name__} gagal: {e}")

    def trigger_event(self, data: Any) -> None:
        self._event_data = data
        self.notify()

    @property
    def state(self) -> Any:
        return self._event_data

# Concrete Observers
class SIEMIntegration(Observer):
    def update(self, subject: SecurityEventBus) -> None:
        data = subject.state
        logger.info(f"[SIEM] Mengirim log ke pusat keamanan: {data}")

class AlertSystem(Observer):
    def update(self, subject: SecurityEventBus) -> None:
        data = subject.state
        if "CRITICAL" in str(data):
            logger.warning(f"[ALERT] Sending SMS/Email untuk event: {data}")
        else:
            logger.info(f"[ALERT] Event tercatat: {data}")

# Usage
if __name__ == "__main__":
    bus = SecurityEventBus()
    siem = SIEMIntegration()
    alert = AlertSystem()

    bus.attach(siem)
    bus.attach(alert)

    # Simulasi event keamanan
    bus.trigger_event({"type": "LOGIN_FAIL", "ip": "192.168.1.5"})
    bus.trigger_event({"type": "CRITICAL", "msg": "SQL Injection Detected"})
```

### Catatan Teknis:
1.  **Memory Management**: Menggunakan `weakref` pada list observer. Pada aplikasi server (seperti Pterodactyl plugin atau daemon monitoring), observer yang sudah tidak dipakai akan di-garbage collected tanpa perlu `detach` manual.
2.  **Error Isolation**: Blok `try-except` di dalam `notify()` wajib. Jika satu observer crash (misal: koneksi SIEM timeout), sistem notifikasi utama tidak boleh down.
3.  **Thread Safety**: Implementasi di atas belum thread-safe. Jika digunakan dalam environment multi-threading (seperti Flask/Django workers), bungkus operasi list `_observers` dengan `threading.Lock`.

Gunakan pola ini untuk decoupling modul keamanan, logging, dan notifikasi agar sistem mudah di-maintain dan diskalakan.
